import React, { useState, useEffect } from 'react';
import { ShieldCheck, Users, FileText, AlertTriangle, CheckCircle, XCircle, LogOut, Search, DollarSign, Lock } from 'lucide-react';
import { MOCK_PENDING_INSTRUCTORS, PRAXI_LOGO_URL, MOCK_TRANSACTIONS } from '../constants';
import { PendingInstructor } from '../types';

interface AdminDashboardProps {
  onLogout: () => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ onLogout }) => {
  const [activeTab, setActiveTab] = useState<'VALIDATION' | 'REPORTS' | 'MONITORING' | 'FINANCE'>('VALIDATION');
  const [pendingList, setPendingList] = useState<PendingInstructor[]>(MOCK_PENDING_INSTRUCTORS);

  // Estado para controle de troca de senha
  const [currentUser, setCurrentUser] = useState<any>(null);
  const [showChangePasswordModal, setShowChangePasswordModal] = useState(false);
  const [newPassword, setNewPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');

  useEffect(() => {
      // Recupera usuário da sessão
      const userStr = localStorage.getItem('praxi_user');
      if (userStr) {
          const user = JSON.parse(userStr);
          setCurrentUser(user);
          // Se for o primeiro acesso (senha provisória), obriga a trocar
          if (user.firstAccess) {
              setShowChangePasswordModal(true);
          }
      }
  }, []);

  const handleAction = (id: string, action: 'APPROVE' | 'REJECT') => {
    setPendingList(prev => prev.map(inst => {
      if (inst.id === id) {
        return { ...inst, status: action === 'APPROVE' ? 'APROVADO' : 'REJEITADO' };
      }
      return inst;
    }));
  };

  const handlePasswordChange = () => {
    if (newPassword.length < 6) {
        alert("A senha deve ter no mínimo 6 caracteres.");
        return;
    }
    if (newPassword !== confirmPassword) {
        alert("As senhas não conferem.");
        return;
    }

    // Atualiza usuário no localStorage removendo a flag de primeiro acesso
    const updatedUser = { ...currentUser, firstAccess: false };
    localStorage.setItem('praxi_user', JSON.stringify(updatedUser));

    setShowChangePasswordModal(false);
    alert("Senha alterada com sucesso!");
  };

  return (
    // MOBILE: flex-col (menu em cima ou embaixo). DESKTOP: flex-row (sidebar lateral).
    <div className="flex flex-col md:flex-row h-full w-full bg-praxi-bg text-white font-sans overflow-hidden relative">

      {/* MODAL DE TROCA DE SENHA OBRIGATÓRIA */}
      {showChangePasswordModal && (
        <div className="absolute inset-0 z-[3000] bg-black/90 backdrop-blur-md flex items-center justify-center p-4">
            <div className="bg-praxi-card border border-red-500/50 p-8 rounded-2xl w-full max-w-md shadow-2xl relative">
                <div className="text-center">
                    <div className="bg-red-500/10 w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-4 border border-red-500/30">
                        <Lock size={32} className="text-red-500" />
                    </div>
                    <h2 className="text-2xl font-bold text-white mb-2">Segurança Obrigatória</h2>
                    <p className="text-praxi-subtext text-sm mb-6">
                        Olá <strong>{currentUser?.name}</strong>. Detectamos que você está usando uma senha provisória. 
                        Para continuar acessando o painel administrativo da PRAXI, você deve definir uma nova senha pessoal.
                    </p>
                </div>

                <div className="space-y-4">
                    <div>
                        <label className="block text-xs font-medium text-praxi-subtext mb-1">Nova Senha</label>
                        <input 
                            type="password" 
                            className="w-full bg-praxi-input border border-praxi-border rounded-lg px-4 py-2 text-white focus:border-praxi-accent outline-none"
                            value={newPassword}
                            onChange={(e) => setNewPassword(e.target.value)}
                        />
                    </div>
                    <div>
                        <label className="block text-xs font-medium text-praxi-subtext mb-1">Confirmar Nova Senha</label>
                        <input 
                            type="password" 
                            className="w-full bg-praxi-input border border-praxi-border rounded-lg px-4 py-2 text-white focus:border-praxi-accent outline-none"
                            value={confirmPassword}
                            onChange={(e) => setConfirmPassword(e.target.value)}
                        />
                    </div>
                    <button 
                        onClick={handlePasswordChange}
                        className="w-full bg-red-600 hover:bg-red-700 text-white font-bold py-3 rounded-lg mt-2 transition-colors"
                    >
                        Atualizar Senha e Acessar
                    </button>
                </div>
            </div>
        </div>
      )}

      {/* Sidebar (Desktop) / Topbar (Mobile) */}
      <aside className="w-full md:w-64 bg-praxi-card border-b md:border-b-0 md:border-r border-praxi-border flex flex-col shrink-0">
        <div className="p-4 md:p-6 border-b border-praxi-border flex items-center justify-between md:justify-start gap-3">
           <div className="flex items-center gap-3">
             <img src={PRAXI_LOGO_URL} alt="Praxi" className="h-6 md:h-8 w-auto" />
             <span className="text-xs font-mono bg-praxi-accent/20 text-praxi-accent px-2 py-1 rounded">ADM</span>
           </div>

           {/* Mobile Logout (Topo) */}
           <button onClick={() => { localStorage.removeItem('praxi_user'); onLogout(); }} className="md:hidden text-red-400">
                <LogOut size={20} />
           </button>
        </div>

        {/* Navigation - Scroll horizontal no mobile, vertical no desktop */}
        <nav className="flex-1 p-2 md:p-4 flex flex-row md:flex-col gap-2 overflow-x-auto md:overflow-visible">
          <button 
            onClick={() => setActiveTab('VALIDATION')}
            className={`flex-none md:w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all whitespace-nowrap ${activeTab === 'VALIDATION' ? 'bg-praxi-accent text-white shadow-lg shadow-praxi-accent/20' : 'text-praxi-subtext hover:bg-white/5'}`}
          >
            <ShieldCheck size={20} />
            <div className="flex flex-col items-start">
               <span className="font-medium">Validação</span>
               <span className="text-[10px] text-white/50">Art. 109/110</span>
            </div>
          </button>

          <button 
            onClick={() => setActiveTab('FINANCE')}
            className={`flex-none md:w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all whitespace-nowrap ${activeTab === 'FINANCE' ? 'bg-praxi-accent text-white shadow-lg shadow-praxi-accent/20' : 'text-praxi-subtext hover:bg-white/5'}`}
          >
            <DollarSign size={20} />
            <span className="font-medium">Financeiro</span>
          </button>

          <button 
            onClick={() => setActiveTab('REPORTS')}
            className={`flex-none md:w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all whitespace-nowrap ${activeTab === 'REPORTS' ? 'bg-praxi-accent text-white shadow-lg shadow-praxi-accent/20' : 'text-praxi-subtext hover:bg-white/5'}`}
          >
            <FileText size={20} />
            <div className="flex flex-col items-start">
               <span className="font-medium">Relatórios</span>
               <span className="text-[10px] text-white/50">Art. 12 (Processo)</span>
            </div>
          </button>

          <button 
            onClick={() => setActiveTab('MONITORING')}
            className={`flex-none md:w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all whitespace-nowrap ${activeTab === 'MONITORING' ? 'bg-praxi-accent text-white shadow-lg shadow-praxi-accent/20' : 'text-praxi-subtext hover:bg-white/5'}`}
          >
            <AlertTriangle size={20} />
            <div className="flex flex-col items-start">
               <span className="font-medium">Fiscalização</span>
               <span className="text-[10px] text-white/50">Art. 129 (Sanções)</span>
            </div>
          </button>
        </nav>

        {/* User Info Footer (Desktop Only) */}
        <div className="hidden md:block p-4 border-t border-praxi-border">
          {currentUser && (
              <div className="mb-4 px-2">
                  <p className="text-xs text-praxi-subtext">Logado como:</p>
                  <p className="text-sm font-bold text-white truncate">{currentUser.name}</p>
                  <p className="text-[10px] text-praxi-subtext truncate">{currentUser.email}</p>
              </div>
          )}
          <button onClick={() => { localStorage.removeItem('praxi_user'); onLogout(); }} className="w-full flex items-center gap-2 px-4 py-2 text-red-400 hover:bg-red-500/10 rounded-lg transition-colors">
            <LogOut size={18} />
            Sair do Painel
          </button>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col overflow-hidden w-full">
        {/* Header (Desktop Only Title, or Simplified on Mobile) */}
        <header className="h-14 md:h-16 border-b border-praxi-border bg-praxi-card/50 backdrop-blur-sm flex items-center justify-between px-4 md:px-8 shrink-0">
          <h2 className="text-sm md:text-xl font-bold truncate">
            {activeTab === 'VALIDATION' && "Conformidade Resolução 1.020/2025"}
            {activeTab === 'FINANCE' && "Gestão de Comissões e Pagamentos"}
            {activeTab === 'REPORTS' && "Processos de Habilitação (Art. 12)"}
            {activeTab === 'MONITORING' && "Fiscalização e Penalidades (Art. 129)"}
          </h2>
          <div className="flex items-center gap-3">
            <span className="text-sm text-praxi-subtext hidden md:block">Administrador</span>
            <div className="w-8 h-8 rounded-full bg-emerald-600 flex items-center justify-center font-bold text-xs md:text-base">A</div>
          </div>
        </header>

        {/* Content Area - Scrollable */}
        <div className="flex-1 overflow-y-auto p-4 md:p-8">

          {activeTab === 'VALIDATION' && (
            <div className="space-y-6">
              <div className="bg-blue-500/10 border border-blue-500/30 p-4 rounded-xl flex items-start gap-3">
                 <ShieldCheck className="text-blue-400 shrink-0 mt-1" size={20} />
                 <div>
                    <h4 className="text-blue-400 font-bold text-sm">Atualização Normativa</h4>
                    <p className="text-xs text-blue-200 mt-1">
                        Os instrutores devem ser validados conforme os Artigos 109, 110 e 128 (Identificação do Veículo) da nova Resolução 1.020/2025.
                    </p>
                 </div>
              </div>

              <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                <h3 className="text-lg font-medium text-praxi-light">Pendentes de Aprovação</h3>
                <div className="relative w-full md:w-auto">
                  <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-praxi-subtext" />
                  <input type="text" placeholder="Buscar por CPF..." className="bg-praxi-input border border-praxi-border rounded-lg pl-9 pr-4 py-2 text-sm focus:border-praxi-accent outline-none w-full md:w-64" />
                </div>
              </div>

              <div className="grid gap-4">
                {pendingList.map((inst) => (
                  <div key={inst.id} className="bg-praxi-card border border-praxi-border rounded-xl p-4 md:p-5 flex flex-col md:flex-row items-start justify-between shadow-lg gap-4">
                    <div className="flex gap-4 w-full">
                      <div className="w-12 h-12 rounded-full bg-praxi-input flex items-center justify-center border border-praxi-border shrink-0">
                        <Users size={24} className="text-praxi-subtext" />
                      </div>
                      <div className="flex-1 min-w-0">
                        <div className="flex flex-wrap items-center gap-2">
                          <h4 className="font-bold text-lg truncate">{inst.name}</h4>
                          <span className={`text-[10px] px-2 py-0.5 rounded-full border ${inst.status === 'PENDENTE' ? 'bg-yellow-500/10 border-yellow-500/30 text-yellow-500' : inst.status === 'APROVADO' ? 'bg-emerald-500/10 border-emerald-500/30 text-emerald-500' : 'bg-red-500/10 border-red-500/30 text-red-500'}`}>
                            {inst.status}
                          </span>
                        </div>
                        <p className="text-sm text-praxi-subtext mt-1 truncate">CPF: {inst.cpf}</p>

                        <div className="mt-4 grid grid-cols-1 md:grid-cols-2 gap-2 text-sm">
                          <div className="flex items-center gap-2">
                            {inst.documents.cnh ? <CheckCircle size={14} className="text-emerald-500 shrink-0" /> : <XCircle size={14} className="text-red-500 shrink-0" />}
                            <span className={inst.documents.cnh ? "text-praxi-light" : "text-red-400"}>CNH Válida</span>
                          </div>
                          <div className="flex items-center gap-2">
                            {inst.documents.courseCert ? <CheckCircle size={14} className="text-emerald-500 shrink-0" /> : <XCircle size={14} className="text-red-500 shrink-0" />}
                            <span className={inst.documents.courseCert ? "text-praxi-light" : "text-red-400"}>Curso de Instrutor</span>
                          </div>
                          <div className="flex items-center gap-2">
                            {inst.documents.crlv ? <CheckCircle size={14} className="text-emerald-500 shrink-0" /> : <XCircle size={14} className="text-red-500 shrink-0" />}
                            <span className={inst.documents.crlv ? "text-praxi-light" : "text-red-400"}>CRLV (Art. 128)</span>
                          </div>
                        </div>
                      </div>
                    </div>

                    <div className="flex flex-row md:flex-col gap-2 w-full md:w-auto">
                      {inst.status === 'PENDENTE' && (
                        <>
                          <button 
                            onClick={() => handleAction(inst.id, 'APPROVE')}
                            className="flex-1 bg-emerald-600 hover:bg-emerald-700 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors flex items-center justify-center gap-2"
                          >
                            <CheckCircle size={16} /> <span className="md:hidden lg:inline">Aprovar</span>
                          </button>
                          <button 
                            onClick={() => handleAction(inst.id, 'REJECT')}
                            className="flex-1 bg-red-500/10 hover:bg-red-500/20 text-red-400 border border-red-500/30 px-4 py-2 rounded-lg text-sm font-medium transition-colors flex items-center justify-center gap-2"
                          >
                            <XCircle size={16} /> <span className="md:hidden lg:inline">Recusar</span>
                          </button>
                        </>
