import { GoogleGenAI, Chat, GenerateContentResponse, Part, Modality } from "@google/genai";
import { SYSTEM_INSTRUCTION } from '../constants';
import { Message } from '../types';

let chatSession: Chat | null = null;

const getClient = (): GoogleGenAI => {
  let apiKey = '';

  // 1. Tenta pegar do process.env (Padrão Node/Vercel)
  try {
    // @ts-ignore
    if (typeof process !== 'undefined' && process.env && process.env.API_KEY) {
      // @ts-ignore
      apiKey = process.env.API_KEY;
    }
  } catch (e) {
    // Ignora erro
  }

  // 2. Fallback para Vite (import.meta.env)
  if (!apiKey) {
    try {
      // @ts-ignore
      if (typeof import.meta !== 'undefined' && import.meta.env) {
        // @ts-ignore
        apiKey = import.meta.env.VITE_GEMINI_API_KEY || import.meta.env.VITE_API_KEY || '';
      }
    } catch (e) {
      // Ignora erro
    }
  }

  if (!apiKey) {
    console.error("API Key is missing.");
    throw new Error("API Key is missing. Verifique as variáveis de ambiente.");
  }

  return new GoogleGenAI({ apiKey });
};

export const initializeChat = () => {
  try {
    const ai = getClient();

    chatSession = ai.chats.create({
      model: 'gemini-2.5-flash',
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.7,
      },
      history: [
        {
          role: 'user',
          parts: [{ text: 'Iniciar conversa.' }],
        },
        {
          role: 'model',
          parts: [{
            text: `Oi! Sou a LIA 😊 Já estou atualizada com a nova **Resolução 1.020/2025** do Contran.
Prefere falar por Texto ⌨️ ou Áudio 🎙️?`
          }],
        }
      ]
    });

  } catch (error) {
    console.error("Failed to initialize chat:", error);
  }
};

export const sendMessageStream = async (
  message: string,
  fileData: { mimeType: string; data: string } | null,
  onChunk: (text: string) => void
): Promise<string> => {

  if (!chatSession) {
    initializeChat();
  }

  if (!chatSession) {
    throw new Error("Chat session could not be initialized.");
  }

  let fullResponse = "";

  try {
    const parts: Part[] = [];

    if (fileData) {
      parts.push({
        inlineData: {
          mimeType: fileData.mimeType,
          data: fileData.data
        }
      });
    }

    if (message) {
      parts.push({ text: message });
    }

    const resultStream = await chatSession.sendMessageStream({
      message: parts
    });

    for await (const chunk of resultStream) {
      const c = chunk as GenerateContentResponse;
      if (c.text) {
        fullResponse += c.text;
        onChunk(fullResponse);
      }
    }

  } catch (error) {
    console.error("Error sending message to Gemini:", error);
    throw error;
  }

  return fullResponse;
};

export const mapMessagesToHistory = (messages: Message[]) => {
  return messages.map(m => ({
    role: m.role,
    parts: [{ text: m.content }]
  }));
};

// Função para gerar áudio com voz humanizada (Gemini TTS)
export const generateGeminiAudio = async (text: string): Promise<string | undefined> => {
  try {
    const ai = getClient();

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-preview-tts',
      contents: [{ parts: [{ text }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: {
              voiceName: 'Kore' // Voz feminina natural
            },
          },
        },
      },
    });

    const audioData =
      response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;

    return audioData;

  } catch (error) {
    console.error("Erro ao gerar áudio com Gemini:", error);
    return undefined;
  }
};

