interface DataCollectionFormProps {
  schema: FormSchema;
  onSubmit: (data: Record<string, string>) => void;
  onCancel: () => void;
}

const DataCollectionForm: React.FC<DataCollectionFormProps> = ({ schema, onSubmit, onCancel }) => {
  const [formData, setFormData] = useState<Record<string, string>>({});

  const handleChange = (fieldId: string, value: string) => {
    setFormData(prev => ({
      ...prev,
      [fieldId]: value
    }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSubmit(formData);
  };

  return (
    <div className="absolute inset-0 z-[2000] bg-black/60 backdrop-blur-sm flex items-end md:items-center justify-center p-0 md:p-4 animate-fade-in">
      <div className="bg-white md:rounded-2xl w-full md:max-w-xl shadow-2xl flex flex-col max-h-[90vh] rounded-t-2xl animate-slide-up">

        {/* Header estilo Planilha */}
        <div className="bg-emerald-600 p-4 rounded-t-2xl flex items-center justify-between shrink-0">
            <div className="flex items-center gap-3">
                <div className="bg-white/20 p-2 rounded-lg text-white">
                    <FileSpreadsheet size={24} />
                </div>
                <div className="text-white">
                    <h2 className="text-lg font-bold leading-tight">{schema.title}</h2>
                    <p className="text-xs text-emerald-100 opacity-90">{schema.description}</p>
                </div>
            </div>
            <button onClick={onCancel} className="text-white/80 hover:text-white transition-colors">
                <X size={24} />
            </button>
        </div>

        {/* Corpo do Formulário (Grid/Tabela) */}
        <form onSubmit={handleSubmit} className="flex-1 overflow-y-auto p-4 md:p-6 bg-slate-50">
            <div className="grid grid-cols-1 gap-4">
                {schema.fields.map((field) => (
                    <div key={field.id} className="bg-white p-3 rounded-lg border border-gray-200 shadow-sm focus-within:ring-2 focus-within:ring-emerald-500 focus-within:border-emerald-500 transition-all">
                        <label className="block text-xs font-bold text-gray-500 uppercase tracking-wider mb-1">
                            {field.label} {field.required && <span className="text-red-500">*</span>}
                        </label>

                        {field.type === 'select' ? (
                            <select
                                required={field.required}
                                value={formData[field.id] || ''}
                                onChange={(e) => handleChange(field.id, e.target.value)}
                                className="w-full bg-transparent text-gray-900 text-base outline-none py-1"
                            >
                                <option value="" disabled>Selecione uma opção</option>
                                {field.options?.map(opt => (
                                    <option key={opt} value={opt}>{opt}</option>
                                ))}
                            </select>
                        ) : (
                            <input 
                                type={field.type}
                                placeholder={field.placeholder}
                                required={field.required}
                                value={formData[field.id] || ''}
                                onChange={(e) => handleChange(field.id, e.target.value)}
                                className="w-full bg-transparent text-gray-900 text-base outline-none py-1 placeholder-gray-300"
                            />
                        )}
                    </div>
                ))}
            </div>
        </form>

        {/* Footer com Ações */}
        <div className="p-4 border-t border-gray-200 bg-white md:rounded-b-2xl flex items-center gap-3 shrink-0">
            <button 
                type="button" 
                onClick={onCancel}
                className="flex-1 py-3.5 rounded-xl border border-gray-300 text-gray-600 font-medium hover:bg-gray-50 transition-colors"
            >
                Cancelar
            </button>
            <button 
                onClick={handleSubmit}
                className="flex-[2] py-3.5 rounded-xl bg-emerald-600 text-white font-bold hover:bg-emerald-700 shadow-lg shadow-emerald-600/20 transition-all active:scale-95 flex items-center justify-center gap-2"
            >
                <Check size={20} />
                Enviar Dados
            </button>
        </div>

      </div>
    </div>
  );
};

