//  ADMINISTRAÇÃO
// ============================================================================

export const getPendingValidations = async (): Promise<PendingInstructor[]> => {
  try {
    const { data, error } = await supabase
      .from('instructor_validations')
      .select('*')
      .eq('status', 'PENDENTE');

    if (error) throw error;

    // Mapeia do formato do banco para o tipo do Front
    return (data || []).map((item: any) => ({
        id: item.id,
        name: item.full_name,
        cpf: item.cpf,
        cnhCategory: 'B', // Default ou extrair de JSON
        courseDate: new Date(item.created_at).toLocaleDateString('pt-BR'),
        vehiclePlate: item.vehicle_plate,
        status: 'PENDENTE',
        documents: item.documents_status || { cnh: false, courseCert: false, crlv: false, backgroundCheck: false }
    }));

  } catch (error) {
    console.error("Erro ao buscar validações:", error);
    return [];
  }
};

