                      </div>
                  </div>

                  {/* NOVO CAMPO: ÚLTIMOS 4 DÍGITOS DO CELULAR */}
                  <div>
                      <label className="block text-xs font-medium text-gray-700 mb-1">Confirmação de Identidade</label>
                      <div className="relative">
                          <Smartphone className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
                          <input 
                            type="text" 
                            value={phoneSuffix}
                            onChange={(e) => {
                                // Apenas números, máx 4 dígitos
                                const val = e.target.value.replace(/\D/g, '').slice(0, 4);
                                setPhoneSuffix(val);
