export const saveFormSubmission = async (formId: string, data: Record<string, string>) => {
  try {
    const { error } = await supabase
      .from('form_submissions')
      .insert([
        { 
          form_type: formId, 
          data: data,
          status: 'PENDING'
        }
      ]);

    if (error) throw error;

    // Se for cadastro de instrutor, já cria uma entrada na tabela de validação também (Mock logic for now)
    if (formId === 'INSTRUCTOR_REGISTER') {
        await supabase.from('instructor_validations').insert([{
            full_name: data.fullName,
            cpf: data.cpf,
            credential_detran: data.credential,
            vehicle_plate: data.vehiclePlate,
            status: 'PENDENTE',
            documents_status: { cnh: false, courseCert: false, crlv: false, backgroundCheck: false }
        }]);
    }

    return true;
  } catch (error) {
    console.error("Erro ao salvar formulário:", error);
    return false;
  }
};

// ============================================================================
//  VERIFICAÇÃO DE USUÁRIO (LOGIN VIA KEYWORD)
// ============================================================================

export const verifyUserByKeyword = async (keyword: string): Promise<{ found: boolean; name?: string; role?: string }> => {
  try {
    // Busca na tabela de submissões onde o JSON contém a chave 'keyword' igual ao valor passado
    // Sintaxe Postgres JSONB: data->>'keyword'
    const { data, error } = await supabase
      .from('form_submissions')
      .select('data')
      .eq('data->>keyword', keyword)
      .limit(1)
      .single();

    if (error || !data) {
        return { found: false };
    }

    // Retorna dados básicos encontrados no formulário
    const userData = data.data as any;
    return { 
        found: true, 
        name: userData.fullName || 'Usuário',
        role: 'user' // Simplificado
    };

  } catch (error) {
    console.error("Erro ao verificar keyword:", error);
    return { found: false };
  }
};

