// Type definition for Web Speech API and PWA
declare global {
  interface Window {
    webkitSpeechRecognition: any;
    SpeechRecognition: any;
    webkitAudioContext: any;
    AudioContext: any;
  }
  interface BeforeInstallPromptEvent extends Event {
    prompt: () => Promise<void>;
    userChoice: Promise<{ outcome: 'accepted' | 'dismissed', platform: string }>;
  }
}

// Funções auxiliares para decodificar áudio PCM do Gemini
function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number = 24000,
  numChannels: number = 1,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

interface ChatInterfaceProps {
  onOpenMap?: () => void;
  onOpenAdmin?: () => void;
}

export const ChatInterface: React.FC<ChatInterfaceProps> = ({ onOpenMap, onOpenAdmin }) => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputValue, setInputValue] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isGeneratingAudio, setIsGeneratingAudio] = useState(false);
  const [isAudioMode, setIsAudioMode] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [showAlerts, setShowAlerts] = useState(false);

  // Estado para formulários dinâmicos
  const [activeFormId, setActiveFormId] = useState<string | null>(null);
  const [isSavingForm, setIsSavingForm] = useState(false); // Feedback visual

  // Estado para PWA
  const [deferredPrompt, setDeferredPrompt] = useState<BeforeInstallPromptEvent | null>(null);
  const [isIOS, setIsIOS] = useState(false);
  const [showIOSInstall, setShowIOSInstall] = useState(false);

  // Estado para o Modal de Login
  const [showLoginModal, setShowLoginModal] = useState(false);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [loginLoading, setLoginLoading] = useState(false);
  const [showEmailToast, setShowEmailToast] = useState(false);
  const [systemEmailSent, setSystemEmailSent] = useState(false);

  // Estados do Formulário de Login
  const [email, setEmail] = useState('');
  const [phoneSuffix, setPhoneSuffix] = useState('');
  const [password, setPassword] = useState('');
  const [loginError, setLoginError] = useState('');

  // Estado para arquivo anexo
  const [selectedFile, setSelectedFile] = useState<{ name: string; type: string; data: string } | null>(null);

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const recognitionRef = useRef<any>(null);
  const inputRef = useRef<HTMLInputElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const activeSourceRef = useRef<AudioBufferSourceNode | null>(null);

  const initAudioContext = async () => {
    if (!audioContextRef.current) {
      const AudioContextClass = window.AudioContext || window.webkitAudioContext;
      audioContextRef.current = new AudioContextClass();
    }
    if (audioContextRef.current.state === 'suspended') {
      await audioContextRef.current.resume();
    }
  };

  useEffect(() => {
    initializeChat();

    // Mensagem de Onboarding com a nova lei
    setMessages([
      {
        id: 'init-1',
        role: Role.MODEL,
        content: `Oi! Sou a LIA 😊 Já estou atualizada com a nova **Resolução 1.020/2025**.
Prefere falar por Texto ⌨️ ou Áudio 🎙️?`,
        timestamp: new Date()
      }
    ]);

    // Simulação: Envio de e-mails para os administradores ao "iniciar" o sistema
    const emailsSent = localStorage.getItem('praxi_admin_emails_sent');
    if (!emailsSent && !systemEmailSent) {
        setTimeout(() => {
            setSystemEmailSent(true);
            localStorage.setItem('praxi_admin_emails_sent', 'true');
        }, 1500);
    }

    // PWA: Check for install prompt (Android/Desktop)
    const handleBeforeInstallPrompt = (e: Event) => {
      e.preventDefault();
      setDeferredPrompt(e as BeforeInstallPromptEvent);
    };
    window.addEventListener('beforeinstallprompt', handleBeforeInstallPrompt);

    // PWA: Check for iOS
    const ios = /iPad|iPhone|iPod/.test(navigator.userAgent) && !(window as any).MSStream;
    // Check if already in standalone mode
    const isStandalone = window.matchMedia('(display-mode: standalone)').matches || (window.navigator as any).standalone;

    if (ios && !isStandalone) {
        setIsIOS(true);
    }

    return () => window.removeEventListener('beforeinstallprompt', handleBeforeInstallPrompt);

  }, []);

  useEffect(() => {
    if (!isLoading && !isGeneratingAudio && !isListening && !showLoginModal && !activeFormId) {
        inputRef.current?.focus();
    }
  }, [isLoading, isGeneratingAudio, isListening, showLoginModal, activeFormId]);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    if (!isGeneratingAudio) {
       scrollToBottom();
    }
  }, [messages.length, isLoading]);

  useEffect(() => {
    if ('webkitSpeechRecognition' in window || 'SpeechRecognition' in window) {
      const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
      recognitionRef.current = new SpeechRecognition();
      recognitionRef.current.continuous = false;
      recognitionRef.current.interimResults = false;
      recognitionRef.current.lang = 'pt-BR';

      recognitionRef.current.onresult = (event: any) => {
        const transcript = event.results[0][0].transcript;
        setInputValue(transcript);
        handleSendMessage(transcript);
      };

      recognitionRef.current.onend = () => {
        setIsListening(false);
      };

      recognitionRef.current.onerror = (event: any) => {
        console.error("Speech recognition error", event.error);
        setIsListening(false);
      };
    }
  }, []);

  const handleInstallClick = async () => {
    if (deferredPrompt) {
      // Android/Chrome Logic
      deferredPrompt.prompt();
      const { outcome } = await deferredPrompt.userChoice;
      if (outcome === 'accepted') {
        setDeferredPrompt(null);
      }
    } else if (isIOS) {
      // iOS Logic: Show Instructions
      setShowIOSInstall(true);
      setTimeout(() => setShowIOSInstall(false), 8000);
    }
  };

  const handleFileSelect = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    if (file.type !== 'application/pdf') {
      alert('Por favor, envie apenas arquivos PDF.');
      return;
    }

    try {
      const reader = new FileReader();
      reader.onload = () => {
        const result = reader.result as string;
        const base64Data = result.split(',')[1];

        setSelectedFile({
          name: file.name,
          type: file.type,
          data: base64Data
        });
      };
      reader.readAsDataURL(file);
    } catch (error) {
      console.error("Erro ao ler arquivo:", error);
    }

    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const clearSelectedFile = () => {
    setSelectedFile(null);
  };

  const stopAudio = () => {
    if (activeSourceRef.current) {
        try {
            activeSourceRef.current.stop();
        } catch (e) { }
        activeSourceRef.current = null;
    }
  };

  const playPcmAudio = async (base64String: string) => {
    try {
      await initAudioContext();

      if (!audioContextRef.current) return;

      stopAudio();

      const audioBuffer = await decodeAudioData(
        decode(base64String),
        audioContextRef.current,
        24000,
        1
      );

      const source = audioContextRef.current.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(audioContextRef.current.destination);

      activeSourceRef.current = source;
      source.start();

      return new Promise<void>((resolve) => {
         source.onended = () => {
           if (activeSourceRef.current === source) {
               activeSourceRef.current = null;
           }
           if (!showLoginModal) inputRef.current?.focus();
           resolve();
         };
      });

    } catch (e) {
      console.error("Erro ao reproduzir áudio PCM:", e);
    }
  };

  const handleAudioError = () => {
    const errorMessage: Message = {
      id: Date.now().toString(),
      role: Role.MODEL,
      content: "Ops... nosso sistema de áudio está instável. Vamos de Texto?",
      timestamp: new Date(),
      isAudio: false
    };

    setMessages(prev => [...prev, errorMessage]);
    setIsAudioMode(false); 
  };

  const speakText = async (text: string, forcePlay: boolean = false) => {
    if (!isAudioMode && !forcePlay) return;

    const cleanText = cleanTextForSpeech(text);
    if (!cleanText) return;

    if (isGeneratingAudio) return;

    setIsGeneratingAudio(true);
    const audioBase64 = await generateGeminiAudio(cleanText);
    setIsGeneratingAudio(false);

    if (audioBase64) {
      await playPcmAudio(audioBase64);
    } else {
      handleAudioError();
    }
  };

  const cleanTextForSpeech = (text: string) => {
    return text
      .replace(/[*_#`]/g, '')
      .replace(/\[([^\]]+)\]\([^)]+\)/g, '$1')
      .replace(/\[ACTION:.*?\]/g, '')
      .replace(/[\u{1F600}-\u{1F64F}\u{1F300}-\u{1F5FF}\u{1F680}-\u{1F6FF}\u{1F700}-\u{1F77F}\u{1F780}-\u{1F7FF}\u{1F800}-\u{1F8FF}\u{1F900}-\u{1F9FF}\u{1FA00}-\u{1FA6F}\u{1FA70}-\u{1FAFF}\u{2600}-\u{26FF}\u{2700}-\u{27BF}]/gu, '')
      .replace(/\{.*?\}/g, '')
      .trim();
  }

  const toggleListening = async () => {
    await initAudioContext();
    if (isListening) {
      recognitionRef.current?.stop();
    } else {
      stopAudio();
      setInputValue('');
      recognitionRef.current?.start();
      setIsListening(true);
    }
  };

  // Função para Limpar/Encerrar a conversa
  const handleEndChat = () => {
    // 1. Para áudio
    stopAudio();
    setIsListening(false);

    // 2. Limpa input
    setInputValue('');
    setSelectedFile(null);
    setActiveFormId(null);

    // 3. Reinicia sessão do Gemini (Limpa contexto do modelo)
    initializeChat();

    // 4. Reseta visualização para mensagem inicial
    setMessages([
      {
        id: Date.now().toString(),
        role: Role.MODEL,
        content: `Oi! Sou a LIA 😊 Já estou atualizada com a nova **Resolução 1.020/2025**.
Prefere falar por Texto ⌨️ ou Áudio 🎙️?`,
        timestamp: new Date()
      }
    ]);
  };

  // Login Seguro (Simulado)
  const handleSecureLogin = async () => {
    setLoginError('');
    setLoginLoading(true);

    await new Promise(resolve => setTimeout(resolve, 1500));

    // Busca usuário pelo e-mail
    const adminUser = ADMIN_USERS.find(
        user => user.email.toLowerCase() === email.toLowerCase()
    );

    if (adminUser) {
        // Validação: Telefone (4 últimos dígitos) + Senha
        const cleanPhone = adminUser.phone.replace(/\D/g, ''); // Remove formatação
        const inputSuffix = phoneSuffix.trim();

        const isPhoneValid = cleanPhone.endsWith(inputSuffix);
        const isPasswordValid = adminUser.tempPass === password;

        if (isPhoneValid && isPasswordValid) {
             localStorage.setItem('praxi_user', JSON.stringify({
                ...adminUser,
                role: 'ADMIN',
                // Se a senha for a padrão '12345678', marca como primeiro acesso para forçar troca
                firstAccess: password === '12345678'
            }));

            setLoginLoading(false);
            setShowLoginModal(false);

            setEmail('');
            setPhoneSuffix('');
            setPassword('');

            setShowEmailToast(true);
            setTimeout(() => setShowEmailToast(false), 3000);

            if (onOpenAdmin) onOpenAdmin();
            return;
        }
    }

    // Se falhar qualquer validação
    setLoginError("Dados inválidos. Verifique E-mail, Final do Celular e Senha.");
    setLoginLoading(false);
  };

  const handleSuggestionSelect = async (prompt: string) => {
    await initAudioContext();
    if (prompt.includes("Áudio")) {
        setIsAudioMode(true);
    } else if (prompt.includes("Texto")) {
        setIsAudioMode(false);
    }
    handleSendMessage(prompt);
  };

  const handleFormSubmit = async (data: Record<string, string>) => {
    if (!activeFormId) return;

    setIsSavingForm(true);

    // 1. Gera Palavra-Chave
    const generatedKeyword = `PRAXI-${Math.floor(1000 + Math.random() * 9000)}`;
    const enrichedData = { ...data, keyword: generatedKeyword };

    // 2. Salva no Supabase
    const success = await saveFormSubmission(activeFormId, enrichedData);
    setIsSavingForm(false);

    // 3. Feedback para a IA
    const feedback = success 
        ? `✅ Dados salvos com sucesso! A Palavra-Chave do usuário é **${generatedKeyword}**.`
        : "⚠️ Houve um erro ao salvar, mas recebi os dados.";

    // Formata os dados para enviar como mensagem oculta para a IA (contexto)
    const formattedData = Object.entries(enrichedData)
      .map(([key, value]) => `**${key}:** ${value}`)
      .join('\n');

    const messageToSend = `[DADOS_FORMULARIO_PREENCHIDO]\nStatus: ${feedback}\n\n${formattedData}`;

    setActiveFormId(null);
    handleSendMessage(messageToSend, true); // true = hidden 
  };

  const handleSendMessage = async (content: string, hiddenFromUI = false) => {
    if ((!content.trim() && !selectedFile) || isLoading || isGeneratingAudio) return;

    await initAudioContext();
    stopAudio();

    const currentModeAudio = isAudioMode;
    const fileToSend = selectedFile;
    setSelectedFile(null);

    const modelMessageId = (Date.now() + 1).toString();

    // Se não for hidden, mostra a mensagem do usuário
    if (!hiddenFromUI) {
      const userMessage: Message = {
        id: Date.now().toString(),
        role: Role.USER,
        content: content,
        timestamp: new Date(),
        isAudio: currentModeAudio,
        attachment: fileToSend ? { name: fileToSend.name, type: fileToSend.type } : undefined
      };
      setMessages((prev) => [...prev, userMessage]);
    } else {
        // Se for hidden (ex: form submit), podemos mostrar uma mensagem de feedback visual
        const feedbackMessage: Message = {
            id: Date.now().toString(),
            role: Role.USER,
            content: "✅ Dados do formulário enviados.",
            timestamp: new Date(),
            isAudio: false
        };
        setMessages((prev) => [...prev, feedbackMessage]);
    }

    setInputValue('');
    setIsLoading(true);

    const modelMessage: Message = {
      id: modelMessageId,
      role: Role.MODEL,
      content: '',
      timestamp: new Date(),
      isAudio: currentModeAudio,
    };

    if (!currentModeAudio) {
        setMessages((prev) => [...prev, modelMessage]);
    }

    let finalResponseText = "";

    try {
      await sendMessageStream(
        content, 
        fileToSend ? { mimeType: fileToSend.type, data: fileToSend.data } : null,
        (streamedText) => {
          finalResponseText = streamedText;

          if (!currentModeAudio) {
              setMessages((prev) => 
                prev.map((msg) => 
                  msg.id === modelMessageId ? { ...msg, content: streamedText.replace(/\[ACTION:.*?\]/g, '') } : msg
                )
              );
          }
      });

      setIsLoading(false);

      // --- PROCESSAMENTO DE ACTIONS ---

      // 1. Action: OPEN_FORM
      const formMatch = finalResponseText.match(/\[ACTION: OPEN_FORM: (.*?)\]/);
      if (formMatch) {
          const formId = formMatch[1];
          if (FORM_SCHEMAS[formId]) {
              setActiveFormId(formId);
          }
          finalResponseText = finalResponseText.replace(formMatch[0], "");
      }

      // 2. Action: CHECK_KEYWORD (Verificar cadastro)
      const keywordMatch = finalResponseText.match(/\[ACTION: CHECK_KEYWORD: (.*?)\]/);
      if (keywordMatch) {
          const keyword = keywordMatch[1].trim();
          setIsLoading(true);

          // Verifica no banco
          const result = await verifyUserByKeyword(keyword);
          setIsLoading(false);

          // Envia resposta oculta para a IA saber o resultado
          const systemFeedback = result.found 
            ? `[SISTEMA] Usuário encontrado: ${result.name}. Dê boas-vindas e pergunte como ajudar.`
            : `[SISTEMA] Palavra-chave "${keyword}" não encontrada. Peça para verificar ou sugerir novo cadastro.`;

          // Injeta a resposta do sistema na conversa (invisível para o usuário, mas a IA lê e responde)
          handleSendMessage(systemFeedback, true); 

          // Remove o comando da resposta visual
          finalResponseText = finalResponseText.replace(keywordMatch[0], "");
      }

      // 3. Action: REQUEST_LOGIN
      if (finalResponseText.includes("[ACTION: REQUEST_LOGIN]")) {
        const savedUserStr = localStorage.getItem('praxi_user');
        let isAdminLoggedIn = false;
        if (savedUserStr) {
             const user = JSON.parse(savedUserStr);
             if (user.role === 'ADMIN') isAdminLoggedIn = true;
        }

        if (!isAdminLoggedIn) {
             setShowLoginModal(true);
        } else if (onOpenAdmin) {
            onOpenAdmin();
        }
        finalResponseText = finalResponseText.replace("[ACTION: REQUEST_LOGIN]", "");
      }

      // 4. Action: SHOW_ALERTS
      if (finalResponseText.includes("[ACTION: SHOW_ALERTS]")) {
        setShowAlerts(true);
        finalResponseText = finalResponseText.replace("[ACTION: SHOW_ALERTS]", "");
      }

      // 5. Action: OPEN_MAP
      if (finalResponseText.includes("[ACTION: OPEN_MAP]") && onOpenMap) {
        onOpenMap();
        return; 
      }

      // 6. Action: OPEN_ADMIN
      if (finalResponseText.includes("[ACTION: OPEN_ADMIN]") && onOpenAdmin) {
        const savedUserStr = localStorage.getItem('praxi_user');
        let hasPermission = false;
        if (savedUserStr) {
            const user = JSON.parse(savedUserStr);
            if (user.role === 'ADMIN') hasPermission = true;
        }

        if (hasPermission) {
            onOpenAdmin();
        } else {
            setShowLoginModal(true);
        }
        return; 
      }

      const visibleText = finalResponseText.replace(/\[ACTION:.*?\]/g, '');

      if (currentModeAudio) {
        const cleanText = cleanTextForSpeech(visibleText);

        const modelAudioMessage: Message = {
            ...modelMessage,
            content: visibleText
        };
        setMessages((prev) => [...prev, modelAudioMessage]);

        if (cleanText) {
            setIsGeneratingAudio(true);
            const audioBase64 = await generateGeminiAudio(cleanText);
            setIsGeneratingAudio(false);

            if (audioBase64) {
               await playPcmAudio(audioBase64);
            } else {
               handleAudioError();
            }
        }
      }

    } catch (error) {
      setIsLoading(false);
      setIsGeneratingAudio(false);
      setMessages((prev) => {
        const exists = prev.find(m => m.id === modelMessageId);
        if (exists) {
            return prev.map(m => m.id === modelMessageId ? { ...m, content: 'Desculpe, encontrei um erro. Tente de novo.' } : m);
        }
        return [...prev, {
          id: Date.now().toString(),
          role: Role.MODEL,
          content: 'Desculpe, encontrei um erro. Tente de novo.',
          timestamp: new Date(),
        }];
      });
    }
  };

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') {
      handleSendMessage(inputValue);
    }
  };

  return (
    <div className="flex flex-col h-full w-full lg:max-w-4xl lg:mx-auto bg-praxi-card lg:rounded-2xl lg:shadow-2xl lg:my-8 lg:h-[85vh] border-0 lg:border border-praxi-border overflow-hidden overflow-x-hidden relative shadow-blue-900/20">

      {/* FORMULÁRIO DINÂMICO OVERLAY */}
      {activeFormId && FORM_SCHEMAS[activeFormId] && (
        <DataCollectionForm 
            schema={FORM_SCHEMAS[activeFormId]}
            onSubmit={handleFormSubmit}
            onCancel={() => setActiveFormId(null)}
        />
      )}

      {/* LOADING OVERLAY QUANDO SALVA */}
      {isSavingForm && (
        <div className="absolute inset-0 z-[2100] bg-black/50 backdrop-blur-sm flex items-center justify-center animate-fade-in">
             <div className="bg-white p-6 rounded-2xl flex flex-col items-center shadow-2xl">
                <Loader2 size={32} className="text-praxi-accent animate-spin mb-2" />
                <p className="text-gray-800 font-bold">Salvando dados...</p>
             </div>
        </div>
      )}

      {/* IOS INSTALL INSTRUCTIONS OVERLAY */}
      {showIOSInstall && (
        <div className="absolute bottom-4 left-1/2 -translate-x-1/2 z-[3000] w-[90%] bg-white text-gray-900 p-4 rounded-xl shadow-2xl animate-slide-up border border-gray-200">
            <div className="flex justify-between items-start mb-2">
                <h4 className="font-bold text-sm">Instalar PRAXI no iPhone</h4>
                <button onClick={() => setShowIOSInstall(false)}><X size={16} className="text-gray-400" /></button>
            </div>
            <ol className="text-xs space-y-2 text-gray-600 list-decimal list-inside">
                <li>Toque no botão <strong>Compartilhar</strong> <span className="inline-block p-1 bg-gray-100 rounded">⎋</span> abaixo.</li>
                <li>Role para baixo e selecione <strong>Adicionar à Tela de Início</strong> <span className="inline-block p-1 bg-gray-100 rounded">➕</span>.</li>
            </ol>
            <div className="absolute -bottom-2 left-1/2 -translate-x-1/2 w-4 h-4 bg-white rotate-45 border-r border-b border-gray-200"></div>
        </div>
      )}

      {/* SIMULAÇÃO DE E-MAIL DO SISTEMA */}
      {systemEmailSent && (
        <div className="absolute top-20 right-4 z-[2000] bg-blue-600 text-white px-4 py-3 rounded-lg shadow-xl animate-slide-up max-w-sm border border-blue-400">
            <div className="flex items-start gap-3">
                <div className="bg-white/20 p-1.5 rounded-full mt-0.5">
                    <Mail size={16} />
                </div>
                <div>
                    <h4 className="font-bold text-sm">Convites de Admin Enviados</h4>
                    <p className="text-xs text-blue-100 mt-1">E-mails de confirmação e senha provisória enviados para:</p>
                    <ul className="text-[10px] mt-1 text-blue-50 list-disc list-inside">
                        <li>fhesantos@gmail.com</li>
                        <li>praxi.mvp@gmail.com</li>
                    </ul>
                </div>
                <button onClick={() => setSystemEmailSent(false)} className="text-blue-200 hover:text-white"><X size={14}/></button>
            </div>
        </div>
      )}

      {/* TOAST E MODAL LOGIN */}
      {showEmailToast && (
          <div className="absolute top-20 left-1/2 -translate-x-1/2 z-[2000] bg-emerald-600 text-white px-6 py-3 rounded-full shadow-2xl flex items-center gap-2 animate-slide-up w-max max-w-[90%]">
              <div className="w-5 h-5 rounded-full bg-white flex items-center justify-center shrink-0">
                  <div className="w-3 h-3 bg-emerald-600 rounded-full"></div>
              </div>
              <span className="font-medium text-sm truncate">Login realizado com sucesso!</span>
          </div>
      )}

      {showLoginModal && (
        <div className="absolute inset-0 z-[2000] bg-black/80 backdrop-blur-sm flex items-center justify-center p-4 animate-fade-in">
           <div className="bg-white rounded-2xl p-6 w-full max-w-sm shadow-2xl relative">
              <button onClick={() => setShowLoginModal(false)} className="absolute top-4 right-4 text-gray-400 hover:text-gray-600"><X size={20} /></button>

              <div className="text-center mb-6">
                  <div className="w-16 h-16 bg-blue-50 rounded-full flex items-center justify-center mx-auto mb-4 border border-blue-100">
                       <Bell size={32} className="text-blue-600" />
                  </div>
                  <h3 className="text-xl font-bold text-gray-900">Acesso Restrito</h3>
                  <p className="text-sm text-gray-500 mt-2">Valide sua identidade com segurança.</p>
              </div>

              <div className="space-y-4">
                  <div>
                      <label className="block text-xs font-medium text-gray-700 mb-1">E-mail</label>
                      <div className="relative">
                          <Mail className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
                          <input 
                            type="email" 
                            value={email}
                            onChange={(e) => setEmail(e.target.value)}
                            placeholder="seu@email.com"
                            className="w-full pl-10 pr-4 py-3 border border-gray-300 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none text-gray-900 text-base"
                          />
                      </div>
                  </div>

                  {/* NOVO CAMPO: ÚLTIMOS 4 DÍGITOS DO CELULAR */}
                  <div>
                      <label className="block text-xs font-medium text-gray-700 mb-1">Confirmação de Identidade</label>
                      <div className="relative">
                          <Smartphone className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
                          <input 
                            type="text" 
                            value={phoneSuffix}
                            onChange={(e) => {
                                // Apenas números, máx 4 dígitos
                                const val = e.target.value.replace(/\D/g, '').slice(0, 4);
                                setPhoneSuffix(val);
                            }}
                            placeholder="4 últimos dígitos do celular"
                            className="w-full pl-10 pr-4 py-3 border border-gray-300 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none text-gray-900 text-base"
                          />
                      </div>
                  </div>

                  <div>
                      <label className="block text-xs font-medium text-gray-700 mb-1">Senha</label>
                      <div className="relative">
                          <Lock className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
                          <input 
                            type="password" 
                            value={password}
                            onChange={(e) => setPassword(e.target.value)}
                            placeholder="••••••••"
                            className="w-full pl-10 pr-4 py-3 border border-gray-300 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none text-gray-900 text-base"
                          />
                      </div>
                  </div>

                  {loginError && (
                      <div className="text-red-500 text-xs bg-red-50 p-2 rounded-lg flex items-center gap-2">
                          <AlertTriangle size={12} /> {loginError}
                      </div>
                  )}

                  <button 
                    onClick={handleSecureLogin}
                    disabled={loginLoading}
                    className="w-full flex items-center justify-center gap-2 bg-blue-600 hover:bg-blue-700 text-white font-bold py-3.5 px-4 rounded-xl transition-all shadow-md active:scale-95 disabled:opacity-70 disabled:cursor-not-allowed text-base"
                  >
                     {loginLoading ? <Loader2 size={20} className="animate-spin" /> : "Entrar no Sistema"}
                  </button>
              </div>

              <p className="text-center text-[10px] text-gray-400 mt-4">
                  Esqueceu a senha? Contate o suporte da PRAXI.
              </p>
           </div>
        </div>
      )}

      {/* Header com Degradê Tom sobre Tom até o Branco */}
      {/* PADDING TOP ajustado para notch: pt-[calc(1rem+env(safe-area-inset-top))] */}
      {/* PADDING LATERAL: pl-[calc(1rem+env(safe-area-inset-left))] pr-[calc(1rem+env(safe-area-inset-right))] + px-4 normal */}
      {/* Landscape mobile: menor padding vertical (py-2) para ganhar espaço */}
      <header className="flex-none flex items-center justify-between pb-4 pt-[calc(1rem+env(safe-area-inset-top))] pl-[calc(1rem+env(safe-area-inset-left))] pr-[calc(1rem+env(safe-area-inset-right))] md:p-6 landscape:py-2 landscape:pb-2 border-b border-gray-200 bg-gradient-to-b from-blue-50 via-white to-white z-10 shrink-0 relative w-full">
        <div className="flex items-center gap-4 relative z-10">
            <div className="relative">
                {/* Landscape: imagem menor */}
                <img src={LIA_AVATAR_URL} alt="LIA" className="w-10 h-10 landscape:w-8 landscape:h-8 md:w-12 md:h-12 rounded-full object-cover border-2 border-praxi-accent shadow-lg shadow-praxi-accent/20 transition-all" />
                <div className="absolute bottom-0 right-0 w-3 h-3 bg-green-500 border-2 border-white rounded-full"></div>
            </div>
            <div>
                <h1 className="text-base md:text-lg font-bold text-gray-900 flex items-center gap-2">
                    LIA
                </h1>
                <p className="text-[10px] md:text-xs text-gray-500 flex items-center gap-1">
                    <Sparkles size={10} className="text-praxi-accent" />
                    Assistente Virtual PRAXI
                </p>
            </div>
        </div>

        {/* LOGO CENTRALIZADO (Posicionamento Absoluto) */}
        <div className="absolute left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2 flex justify-center items-center pointer-events-none z-20 pt-[calc(env(safe-area-inset-top)/2)]">
            <img 
                src={PRAXI_LOGO_URL} 
                alt="PRAXI" 
                className="h-10 landscape:h-8 md:h-14 w-auto object-contain drop-shadow-sm opacity-90 transition-all" 
            />
        </div>

        <div className="flex items-center gap-3 relative z-10">
             {/* INSTALL APP BUTTON */}
             {(deferredPrompt || isIOS) && (
                <button 
                    onClick={handleInstallClick}
                    className="p-2 rounded-lg bg-emerald-50 border border-emerald-200 text-emerald-600 hover:bg-emerald-100 transition-colors animate-pulse-fast"
                    title="Instalar Aplicativo"
                >
                    <Download size={18} />
                </button>
             )}

            <div className="h-8 w-px bg-gray-200 hidden md:block"></div>

            <button 
                onClick={handleEndChat}
                className="p-2 rounded-lg bg-red-50 border border-red-200 text-red-500 hover:bg-red-100 transition-colors"
                title="Encerrar Conversa e Limpar Histórico"
            >
                <Trash2 size={18} />
            </button>
            <div className="h-8 w-px bg-gray-200 hidden md:block"></div>
            <button 
                onClick={() => setIsAudioMode(!isAudioMode)}
                className={`p-2 rounded-lg border transition-all ${isAudioMode ? 'bg-sky-50 border-praxi-accent text-praxi-accent shadow-[0_0_10px_rgba(14,165,233,0.3)]' : 'bg-gray-100 border-gray-200 text-gray-500 hover:text-gray-900 hover:bg-gray-200'}`}
                title={isAudioMode ? "Modo Áudio Ativado" : "Modo Texto Ativado"}
            >
                {isAudioMode ? <Volume2 size={18} /> : <VolumeX size={18} />}
            </button>
        </div>
      </header>

      {/* ALERTAS INTELIGENTES (Overlay) */}
      {showAlerts && (
         <div className="absolute top-20 right-4 z-40 w-80 max-w-[90vw] bg-praxi-input border border-praxi-border rounded-xl shadow-2xl animate-fade-in overflow-hidden">
            <div className="bg-praxi-accent/10 p-3 border-b border-praxi-border flex justify-between items-center">
                <h3 className="text-sm font-bold text-praxi-accent flex items-center gap-2">
                    <Bell size={16} /> Alertas Ativos
                </h3>
                <button onClick={() => setShowAlerts(false)} className="text-praxi-subtext hover:text-white"><X size={16} /></button>
            </div>
            <div className="max-h-64 overflow-y-auto">
                {MOCK_ALERTS.map(alert => (
                    <div key={alert.id} className="p-3 border-b border-praxi-border/50 hover:bg-white/5 transition-colors">
                        <div className="flex items-start gap-3">
                            <div className={`mt-1 p-1.5 rounded-full ${alert.severity === 'HIGH' ? 'bg-red-500/20 text-red-400' : 'bg-yellow-500/20 text-yellow-400'}`}>
                                <AlertTriangle size={14} />
                            </div>
                            <div>
                                <h4 className="text-sm font-bold text-white">{alert.title}</h4>
                                <p className="text-xs text-praxi-subtext mt-0.5">{alert.description}</p>
                                <div className="flex items-center gap-1 mt-2 text-[10px] text-praxi-subtext/70">
                                    <Calendar size={10} />
                                    {alert.date}
                                </div>
                            </div>
                        </div>
                    </div>
                ))}
            </div>
            <div className="p-2 bg-praxi-card/50 text-center">
                <button onClick={() => setShowAlerts(false)} className="text-xs text-praxi-accent hover:underline">Fechar Alertas</button>
            </div>
         </div>
      )}

      {/* Messages Area */}
      {/* PADDING LATERAL: pl-[calc(1rem+env(safe-area-inset-left))] pr-[calc(1rem+env(safe-area-inset-right))] */}
      <div className="flex-1 overflow-y-auto p-4 pl-[calc(1rem+env(safe-area-inset-left))] pr-[calc(1rem+env(safe-area-inset-right))] md:p-6 pb-4 space-y-6 scroll-smooth overscroll-contain bg-gradient-to-b from-praxi-card to-praxi-bg w-full">

        {/* LOGO INSERIDO AQUI */}
        <div className="flex w-full justify-center mt-2 mb-4">
          <img 
            src="https://drive.google.com/uc?export=view&id=1CbLjfgjE0Ct9NDuiN3BK5_sW-YUL8wcq" 
            alt="PRAXI Logo" 
            className="h-10 object-contain opacity-90"
          />
        </div>

        {messages.map((msg) => (
          <MessageBubble 
            key={msg.id} 
            message={msg} 
            onPlayAudio={(text) => speakText(text, true)} 
            onStopAudio={stopAudio}
          />
        ))}

        {isLoading && !isAudioMode && (
          <div className="animate-fade-in pl-2">
             <TypingIndicator />
          </div>
        )}

        {(isGeneratingAudio || (isLoading && isAudioMode)) && (
            <div className="flex items-center gap-2 text-emerald-500 text-sm animate-pulse pl-4 font-medium italic">
                <Mic size={16} className="animate-pulse" />
                LIA gravando áudio...
            </div>
        )}

        <div ref={messagesEndRef} />
      </div>

      {/* Input Area */}
      {/* PADDING BOTTOM ajustado para home indicator: pb-[calc(0.75rem+env(safe-area-inset-bottom))] */}
      {/* PADDING LATERAL: pl-[calc(0.75rem+env(safe-area-inset-left))] pr-[calc(0.75rem+env(safe-area-inset-right))] */}
      {/* Landscape mobile: menor padding (p-2) */}
      <div className="flex-none bg-praxi-card border-t border-praxi-border relative z-20 w-full transition-all pt-3 pb-[calc(0.75rem+env(safe-area-inset-bottom))] pl-[calc(0.75rem+env(safe-area-inset-left))] pr-[calc(0.75rem+env(safe-area-inset-right))] md:p-6 landscape:py-2 landscape:pb-[calc(0.5rem+env(safe-area-inset-bottom))]">

        {selectedFile && (
            <div className="absolute -top-12 left-6 bg-praxi-input border border-praxi-border rounded-lg px-3 py-2 flex items-center gap-2 text-sm shadow-lg animate-slide-up">
                <FileText size={16} className="text-red-400" />
                <span className="text-white truncate max-w-[200px]">{selectedFile.name}</span>
                <button onClick={clearSelectedFile} className="ml-2 text-praxi-subtext hover:text-white"><X size={14} /></button>
            </div>
        )}

        {messages.length < 3 && !isLoading && !isGeneratingAudio && (
            <SuggestionChips 
                suggestions={INITIAL_SUGGESTIONS} 
                onSelect={handleSuggestionSelect} 
                disabled={isLoading}
            />
        )}

        <div className="flex gap-2 md:gap-3 items-center relative w-full">
          <input 
            type="file" 
            ref={fileInputRef}
            onChange={handleFileSelect}
            className="hidden"
            accept="application/pdf"
          />
          <button
            onClick={() => fileInputRef.current?.click()}
            disabled={isLoading || isGeneratingAudio}
            className="p-3 landscape:p-2 md:p-3.5 rounded-xl bg-praxi-input text-praxi-subtext hover:bg-praxi-border border border-praxi-border shadow-lg transition-all active:scale-95 flex items-center justify-center disabled:opacity-50 shrink-0"
            title="Anexar PDF"
          >
            <Paperclip size={20} />
          </button>

          <button
            onClick={toggleListening}
            disabled={isLoading || isGeneratingAudio}
            className={`
                p-3 landscape:p-2 md:p-3.5 rounded-xl font-bold shadow-lg transition-all active:scale-95 flex items-center justify-center shrink-0
                ${isListening 
                    ? 'bg-red-500 text-white animate-pulse shadow-red-500/20' 
                    : isAudioMode 
                        ? 'bg-praxi-accent text-white hover:bg-praxi-accentHover shadow-praxi-accent/20' 
                        : 'bg-praxi-input text-praxi-subtext hover:bg-praxi-border border border-praxi-border'
                }
            `}
            title="Falar"
          >
             {isListening ? <StopCircle size={20} /> : <Mic size={20} />}
          </button>

          <input
            ref={inputRef}
            type="text"
            value={inputValue}
            onChange={(e) => setInputValue(e.target.value)}
            onKeyDown={handleKeyPress}
            autoFocus
            placeholder={isListening ? "Ouvindo..." : isAudioMode ? "Fale ou digite..." : selectedFile ? "Descreva o arquivo..." : "Digite sua mensagem..."}
            disabled={isLoading || isGeneratingAudio}
            // text-base impede zoom no iOS
            // landscape:py-2 para input mais fino
            // min-w-0 corrige o bug de overflow em flex container
            className="flex-1 min-w-0 bg-praxi-input text-white rounded-xl px-4 py-3 landscape:py-2 md:py-3.5 outline-none focus:ring-2 focus:ring-praxi-accent/50 transition-all border border-praxi-border placeholder-praxi-subtext/50 disabled:opacity-50 text-base"
          />
          <button
            onClick={() => handleSendMessage(inputValue)}
            disabled={(!inputValue.trim() && !selectedFile) || isLoading || isGeneratingAudio}
            className="p-3 landscape:p-2 md:p-3.5 bg-praxi-accent hover:bg-praxi-accentHover text-white rounded-xl font-bold shadow-lg shadow-praxi-accent/20 disabled:opacity-50 disabled:cursor-not-allowed transition-transform active:scale-95 flex items-center justify-center shrink-0"
          >
            <Send size={20} />
          </button>
        </div>
        <div className="text-center mt-2 md:mt-3 landscape:hidden">
             <p className="text-[10px] text-praxi-subtext/70">
                {isAudioMode ? "Modo Áudio Ativo" : "Modo Texto Ativo"}
             </p>
        </div>
      </div>
    </div>
  );
};
